80	/** 判定节奏命中：返回命中的天数索引，未命中返回-1 */
81	function rhythmHit(days, rhythmArr) {
82	  // 找到 days 落在哪个间隔的 ±0 容差内 (当天命中)
83	  for (let i = 0; i < rhythmArr.length; i++) {
84	    const cumulative = rhythmArr.slice(0, i + 1).reduce((a, b) => a + b, 0);
85	    if (days === cumulative) return i;
86	  }
87	  return -1;
88	}
