378	/** 计算SOON因子命中 */
379	function computeFactors(stage, bl, meta, daysSinceMsg, lastSenderIsMe) {
380	  const factors = [];
381	  const t = TODAY_DATE;
382	
383	  switch (stage) {
384	    case '需求探索': {
385	      const d = parseDate(bl.S1);
386	      if (!d) break;
387	      const days = daysBetween(d, t);
388	      if (days < 1) break;
389	      const hitIdx = rhythmHit(days, RHYTHM.S1);
390	      if (hitIdx >= 0) {
391	        const cumulative = RHYTHM.S1.slice(0, hitIdx + 1).reduce((a, b) => a + b, 0);
