183	      case "S9 该接触了":
184	        level = "yellow";
185	        title = `该接触——待返单客户定期触达`;
186	        detail = `待返单${days}天，按节奏定期触达。同步新品/行业信息/工厂动态维持存在感。`;
187	        break;
188	
189	      default:
190	        title = f.factor;
191	        detail = `${days}天前基线(${f.baseline || "?"})`;
192	    }
193	
194	    return { level, title, detail, factor: f.factor };
195	  });
196	}
