202	function makeBadge(f, daysSince) {
203	  const code = (f.factor || "").split("(")[0].trim();
204	  const days = f.days || daysSince || 0;
205	  const isObserve = !!f.observeMode;
206	  const isHigh = f.priority === "high";
207	  const isDoudi = (f.factor || "").includes("兜底");
208	
209	  switch (code) {
210	    case "S3 该推进了":
211	      if (days <= 3) return `未回${days}d`;
212	      if (days <= 7) return `沉默${days}d`;
213	      return `推进${days}d`;
214	    case "S4 该催款了":
215	      if (isObserve) return "催款观察";
216	      return `催款${days}d`;
217	    case "S1 该深挖需求了":
218	      if (isDoudi) return `兜底${days}d`;
219	      return `深挖${days}d`;
220	    case "S2 该追问了":
221	      return `追问${days}d`;
222	    case "S5a 该更新进度了":
223	      if (isHigh) return "超期!";
224	      return `进度${days}d`;
225	    case "S6 该更新物流了":
226	      return "物流";
227	    case "S7a 该回访了":
228	      return "回访";
229	    case "S7b 该推返单了":
230	      return "返单";
231	    case "S8 该收尾了":
232	      return "收尾";
233	    case "S9 该接触了":
234	      return "接触";
235	    default:
236	      return "待办";
237	  }
238	}
