244	function loadJSON(filename) {
245	  const p = path.join(OUTPUT_DIR, filename);
246	  if (!fs.existsSync(p)) return null;
247	  return JSON.parse(fs.readFileSync(p, "utf-8"));
248	}
249	
250	function parseFrontmatter(content) {
251	  const match = content.match(/^---\s*\n([\s\S]*?)\n---/);
252	  if (!match) return {};
253	  const fm = {};
254	  for (const line of match[1].split("\n")) {
255	    const kv = line.match(/^(\w+):\s*(.+)$/);
256	    if (kv) fm[kv[1]] = kv[2].trim();
257	  }
258	  return fm;
259	}
260	
261	function extractSection(content, heading) {
262	  const re = new RegExp(`## ${heading}\\s*\\n([\\s\\S]*?)(?=\\n## |$)`, "i");
263	  const m = content.match(re);
264	  return m ? m[1].trim() : "";
265	}
266	
267	/** 从"最近动态"区块提取结构化聊天行 */
268	function extractChatLines(content) {
269	  const section = extractSection(content, "最近动态");
270	  if (!section) return [];
271	  const lines = [];
272	  // 格式1: - 2026-05-09 我: hello world（MsgID:xxx）
273	  // 格式2: - 2026-05-09 我催单：hello world
274	  // 格式3: [初稿] 最近5条消息摘要：...
275	  const chatRe = /^-\s*(\d{4}-\d{2}-\d{2})\s+(我|客)(?:催单|告知|跟进|回复|追问|)?[：:]\s*(.+?)(?:（MsgID:[\w.]+）)?$/;
276	  for (const raw of section.split("\n")) {
277	    const line = raw.trim();
278	    if (!line.startsWith("- ")) continue;
279	    if (line.includes("[初稿]") || line.includes("最近5条消息摘要")) continue;
280	    const m = line.match(chatRe);
281	    if (m) {
282	      lines.push({
283	        who: m[2] === "我" ? "me" : "cust",
284	        time: m[1].slice(5), // MM-DD
285	        text: m[3].trim().substring(0, 150),
286	      });
287	    } else {
288	      // 宽松匹配
289	      const loose = line.match(/^-\s*(\d{4}-\d{2}-\d{2})\s+(.+)$/);
290	      if (loose) {
291	        const rest = loose[2];
292	        const whoStr = rest.startsWith("我") ? "me" : rest.startsWith("客") ? "cust" : null;
293	        if (whoStr) {
294	          const text = rest.replace(/^[我客](?:催单|告知|跟进|回复|追问|)?[：:]?\s*/, "").replace(/（MsgID:[\w.]+）$/, "").trim();
295	          lines.push({ who: whoStr, time: loose[1].slice(5), text: text.substring(0, 150) });
296	        }
297	      }
298	    }
299	  }
300	  return lines.slice(-6); // 最近6条
301	}
302	
303	function extractKeyNums(content) {
304	  const section = extractSection(content, "关键数字");
305	  if (!section) return [];
306	  return section.split("\n")
307	    .filter(l => l.trim().startsWith("-") && !l.includes("[初稿]"))
308	    .map(l => l.replace(/^-\s*/, "").trim())
309	    .filter(Boolean);
310	}
311	
312	function extractNextStep(content) {
313	  const section = extractSection(content, "下一步");
314	  const lines = section.split("\n").filter(l => l.trim().startsWith("→"));
315	  if (lines.length > 0) {
316	    return lines.map(l => l.replace(/^→\s*(?:\[初稿\]\s*)?/, "").trim()).join("\n");
317	  }
318	  return section.replace(/^→\s*(?:\[初稿\]\s*)?/, "").trim().substring(0, 120);
319	}
320	
321	function loadBriefs() {
322	  const map = {};
323	  if (!fs.existsSync(BRIEFS_DIR)) return map;
324	  for (const file of fs.readdirSync(BRIEFS_DIR)) {
325	    if (!file.endsWith(".md")) continue;
326	    const content = fs.readFileSync(path.join(BRIEFS_DIR, file), "utf-8");
327	    const fm = parseFrontmatter(content);
328	    if (fm.cid) map[fm.cid] = { frontmatter: fm, content, file };
329	  }
330	  return map;
331	}
