337	function buildCustomerCards() {
338	  const baselines = loadJSON("factor_baselines.json");
339	  const soon = loadJSON("soon_layer_cards.json");
340	  const cold = loadJSON("cold_layer_stratification.json");
341	  const briefs = loadBriefs();
342	
343	  if (!baselines) {
344	    console.error("factor_baselines.json 不存在，请先运行 init_factor_baselines.js");
345	    return null;
346	  }
347	
348	  const factorMap = new Map();
349	  if (soon) for (const c of soon.customers || []) factorMap.set(c.cid, c);
350	
351	  const coldCids = new Set();
352	  if (cold) {
353	    for (const layer of Object.values(cold.frozen || {})) {
354	      for (const c of layer) coldCids.add(c.cid);
355	    }
356	  }
357	
358	  const cards = [];
359	
360	  for (const [cid, data] of Object.entries(baselines)) {
361	    const stage = data.stage || "未知";
362	    const soonData = factorMap.get(cid);
363	    const factors = soonData ? soonData.factors : [];
364	    const brief = briefs[cid];
365	    const briefHeat = (brief && brief.frontmatter && brief.frontmatter.heat) || null;
366	    const urgencyKey = coldCids.has(cid) ? "frozen" : classifyUrgency(factors, briefHeat);
367	    const tier = (data.meta && data.meta.customer_tier) || "C";
368	
369	    let daysSince = null, lastContactDate = null, firstContact = null;
370	    if (data.baselines) {
371	      let latest = null, earliest = null;
372	      for (const v of Object.values(data.baselines)) {
373	        if (v) {
374	          if (!latest || v > latest) latest = v;
375	          if (!earliest || v < earliest) earliest = v;
376	        }
377	      }
378	      if (latest) { lastContactDate = latest; daysSince = Math.floor((new Date(TODAY) - new Date(latest)) / 86400000); }
379	      firstContact = earliest;
380	    }
381	
382	    let chatLines = [], keyNums = [], nextStep = "";
383	
384	    // 服务端生成富驱动因子描述
385	    const richDrivers = factors.length > 0
386	      ? buildRichDrivers(factors, stage, daysSince, brief ? brief.content : null)
387	      : [];
388	
389	    if (brief) {
390	      chatLines = extractChatLines(brief.content);
391	      keyNums = extractKeyNums(brief.content);
392	      nextStep = extractNextStep(brief.content);
393	    }
394	
395	    cards.push({
396	      cid,
397	      name: data.name || "?",
398	      country: data.country || "?",
399	      countryCN: countryCN(data.country),
400	      stage,
401	      colKey: stageColKey(stage),
402	      tier,
403	      urgencyKey,
404	      factors,
405	      richDrivers,       // 服务端预生成的驱动因子描述
406	      daysSince,
407	      lastContactDate,
408	      firstContact,
409	      chatLines,         // 结构化聊天行
410	      keyNums,
411	      nextStep,
412	      hasBrief: !!brief,
413	      briefFile: brief ? brief.file : null,
414	    });
415	  }
416	
417	  return cards;
418	}
