208	  const snippetText = (c.snippet || []).join(' ');
209	  const gradeResult = correctGrade(c, snippetText);
210	  const finalGrade = gradeResult.grade;
211	
212	  const entry = {
213	    name: c.name,
214	    cid: c.cid,
215	    country: c.country,
216	    stage: cls.stage,
217	    grade: finalGrade,
218	    priority: cls.priority,
219	    actionHint: cls.reason,
220	    reason: cls.reason,
221	    confidence: 'high',
222	    actionPriority: cls.priority,
223	    stageLabel: cls.stage,
224	    actionStatus: cls.priority === 'now' ? '紧急' : (cls.priority === 'soon' ? '尽快处理' : '观察'),
225	    actionText: cls.reason
226	  };
227	  if (gradeResult.override) {
228	    entry.gradeOverride = gradeResult.override;
229	    gradeCorrections++;
230	  }
231	
232	  results.push(entry);
233	  stageDist[cls.stage] = (stageDist[cls.stage] || 0) + 1;
234	  priorityDist[cls.priority] = (priorityDist[cls.priority] || 0) + 1;
235	  gradeDist[finalGrade] = (gradeDist[finalGrade] || 0) + 1;
